def _has_odd_hole(H):
    nodes = list(H.nodes())
    for k in range(5, len(nodes) + 1, 2):
        for subset in itertools.combinations(nodes, k):
            sub = H.subgraph(subset)
            if sub.number_of_edges() == k and all(deg == 2 for _, deg in sub.degree()) and nx.is_connected(sub):
                return True
    return False
